import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.android_studio
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.intellij_idea
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for Issue 1756: Lambda parameters should be correctly indented when the lambda
 * is on a continuation line (i.e., the function call has wrapped arguments and the lambda
 * is on a separate line from the function name).
 *
 * See: https://github.com/pinterest/ktlint/issues/1756
 */
class IndentationRuleLambdaParameterIssue1756Test {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Nested
    inner class `Given a function call with wrapped arguments followed by a lambda with parameters on multiple lines` {
        private val code =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                c(a, b)
            }

            class Foo {
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                        b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()

        @Test
        fun `Given ktlint_official code style then expect no violations`() {
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given intellij_idea code style then expect no violations`() {
            // With the fix, lambda parameters on a continuation line should use double indent
            // instead of trying to align with a function name that's on a different line
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given android_studio code style then expect no violations`() {
            // With the fix, lambda parameters on a continuation line should use double indent
            // instead of trying to align with a function name that's on a different line
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to android_studio)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given a function call without wrapped arguments with lambda on same line` {
        private val code =
            """
            class Foo {
                fun foo() {
                    combine { a,
                              b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()

        @Test
        fun `Given ktlint_official code style then double indent is expected`() {
            val formattedCode =
                """
                class Foo {
                    fun foo() {
                        combine { a,
                                b ->
                            TODO()
                        }
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .isFormattedAs(formattedCode)
        }

        @Test
        fun `Given intellij_idea code style then alignment with first parameter is expected`() {
            // In IntelliJ IDEA style, when the lambda is on the same line as the function call,
            // parameters should be aligned with the first parameter
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given a trailing lambda with first parameter on newline` {
        private val code =
            """
            class Foo {
                fun foo() {
                    combine {
                            a,
                            b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()

        @Test
        fun `Given ktlint_official code style then expect no violations with double indent`() {
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given intellij_idea code style then expect no violations with double indent`() {
            // When the first parameter is on a newline, double indent is used for all code styles
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to intellij_idea)
                .hasNoLintViolations()
        }
    }
}
